function i(n){return String(n||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toUpperCase().replace(/\s+/g," ").trim()}function r(n){let e=i(n);return e?e.includes("ORANGE DIGITAL KALANSO")||e.includes("ODK")||e.includes("ORANGE DIGITAL MULTIMEDIA")||e.includes("MULTIMEDIA")||e.includes("ORANGE FABLAB")||e.includes("FABLAB")||e.includes("ORANGE FAB"):!1}function t(n){return n.filter(e=>r(e?.nom))}export{r as a,t as b};
